// // This module implements a 8-bit register with disable functionality. When disable is high, the register holds its current value.
module top_module(
	input clk,
	input reset,
	input enable,
	input [7:0] d,
	output reg [7:0] q);always @(posedge clk)
		if (reset)
			q <= 8'b00000000;
		else if (enable)
			q <= d;

endmodule
